 {"id":"bd-6sq","title":"Implement ServerStats struct for runtime metrics","description":"## Purpose and Rationale

Create a data structure that tracks server runtime metrics (requests, connections, timing, etc.) which will be displayed using rich_rust components. This separates data collection from presentation.

## Background

A premium MCP server experience requires visibility into what the server is doing. Metrics like request counts, average latency, active connections, and uptime help both developers and operators understand server health. These metrics will be rendered as beautiful tables and panels.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/stats/mod.rs

use std::sync::atomic::{AtomicU64, AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

/// Thread-safe server statistics collector
#[derive(Debug, Clone)]
pub struct ServerStats {
    inner: Arc<ServerStatsInner>,
}

#[derive(Debug)]
struct ServerStatsInner {
    // Timing
    start_time: Instant,

    // Request counters
    total_requests: AtomicU64,
    successful_requests: AtomicU64,
    failed_requests: AtomicU64,
    cancelled_requests: AtomicU64,

    // By method type
    tool_calls: AtomicU64,
    resource_reads: AtomicU64,
    prompt_gets: AtomicU64,
    list_operations: AtomicU64,

    // Latency tracking (approximate)
    total_latency_micros: AtomicU64,
    max_latency_micros: AtomicU64,
    min_latency_micros: AtomicU64,

    // Connection state
    active_connections: AtomicUsize,
    total_connections: AtomicU64,

    // Data transfer
    bytes_received: AtomicU64,
    bytes_sent: AtomicU64,
}

impl ServerStats {
    pub fn new() -> Self {
        Self {
            inner: Arc::new(ServerStatsInner {
                start_time: Instant::now(),
                total_requests: AtomicU64::new(0),
                successful_requests: AtomicU64::new(0),
                failed_requests: AtomicU64::new(0),
                cancelled_requests: AtomicU64::new(0),
                tool_calls: AtomicU64::new(0),
                resource_reads: AtomicU64::new(0),
                prompt_gets: AtomicU64::new(0),
                list_operations: AtomicU64::new(0),
                total_latency_micros: AtomicU64::new(0),
                max_latency_micros: AtomicU64::new(0),
                min_latency_micros: AtomicU64::new(u64::MAX),
                active_connections: AtomicUsize::new(0),
                total_connections: AtomicU64::new(0),
                bytes_received: AtomicU64::new(0),
                bytes_sent: AtomicU64::new(0),
            }),
        }
    }

    /// Record a completed request
    pub fn record_request(&self, method: &str, latency: Duration, success: bool) {
        self.inner.total_requests.fetch_add(1, Ordering::Relaxed);

        if success {
            self.inner.successful_requests.fetch_add(1, Ordering::Relaxed);
        } else {
            self.inner.failed_requests.fetch_add(1, Ordering::Relaxed);
        }

        // Track by method type
        match method {
            m if m.starts_with("tools/") => {
                self.inner.tool_calls.fetch_add(1, Ordering::Relaxed);
            }
            m if m.starts_with("resources/") => {
                self.inner.resource_reads.fetch_add(1, Ordering::Relaxed);
            }
            m if m.starts_with("prompts/") => {
                self.inner.prompt_gets.fetch_add(1, Ordering::Relaxed);
            }
            _ if method.contains("list") => {
                self.inner.list_operations.fetch_add(1, Ordering::Relaxed);
            }
            _ => {}
        }

        // Track latency
        let micros = latency.as_micros() as u64;
        self.inner.total_latency_micros.fetch_add(micros, Ordering::Relaxed);
        self.inner.max_latency_micros.fetch_max(micros, Ordering::Relaxed);
        self.inner.min_latency_micros.fetch_min(micros, Ordering::Relaxed);
    }

    /// Get a snapshot for display
    pub fn snapshot(&self) -> StatsSnapshot {
        let total = self.inner.total_requests.load(Ordering::Relaxed);
        let total_latency = self.inner.total_latency_micros.load(Ordering::Relaxed);

        StatsSnapshot {
            uptime: self.inner.start_time.elapsed(),
            total_requests: total,
            successful_requests: self.inner.successful_requests.load(Ordering::Relaxed),
            failed_requests: self.inner.failed_requests.load(Ordering::Relaxed),
            cancelled_requests: self.inner.cancelled_requests.load(Ordering::Relaxed),
            tool_calls: self.inner.tool_calls.load(Ordering::Relaxed),
            resource_reads: self.inner.resource_reads.load(Ordering::Relaxed),
            prompt_gets: self.inner.prompt_gets.load(Ordering::Relaxed),
            avg_latency: if total > 0 {
                Duration::from_micros(total_latency / total)
            } else {
                Duration::ZERO
            },
            max_latency: Duration::from_micros(self.inner.max_latency_micros.load(Ordering::Relaxed)),
            active_connections: self.inner.active_connections.load(Ordering::Relaxed),
            bytes_received: self.inner.bytes_received.load(Ordering::Relaxed),
            bytes_sent: self.inner.bytes_sent.load(Ordering::Relaxed),
        }
    }
}

/// Point-in-time snapshot of server statistics
#[derive(Debug, Clone)]
pub struct StatsSnapshot {
    pub uptime: Duration,
    pub total_requests: u64,
    pub successful_requests: u64,
    pub failed_requests: u64,
    pub cancelled_requests: u64,
    pub tool_calls: u64,
    pub resource_reads: u64,
    pub prompt_gets: u64,
    pub avg_latency: Duration,
    pub max_latency: Duration,
    pub active_connections: usize,
    pub bytes_received: u64,
    pub bytes_sent: u64,
}
```

