}
EOF

# Build fastmcp CLI
log "INFO" "Building fastmcp CLI..."
cargo build -p fastmcp-cli 2>&1 | tee -a "$LOG_FILE"

FASTMCP="./target/debug/fastmcp"

# Test 1: Start dev mode
