sleep 5

if kill -0 "$DEV_PID" 2>/dev/null; then
    log "INFO" "PASS: Dev mode started"
else
    log "ERROR" "FAIL: Dev mode failed to start"
    cat /tmp/dev_output_$$.log
    exit 1
fi

# Check initial version
if grep -q "VERSION=1" /tmp/dev_output_$$.log; then
    log "INFO" "PASS: Initial version running"
else
    log "ERROR" "FAIL: Initial version not detected"
    exit 1
fi

# Kill for reload test
kill "$DEV_PID" 2>/dev/null || true
sleep 1

# Test 2: Hot reload
log "INFO" "Test 2: Hot reload on file change"
$FASTMCP dev "$TEST_PROJECT" > /tmp/dev_output_$$.log 2>&1 &
DEV_PID=$!
sleep 5

# Modify source
cat > "$TEST_PROJECT/src/main.rs" << 'EOF'
fn main() {
    eprintln!("VERSION=2");
    loop { std::thread::sleep(std::time::Duration::from_secs(1)); }
}
EOF

# Wait for rebuild and restart
sleep 10

if grep -q "VERSION=2" /tmp/dev_output_$$.log; then
